(async function() {
  try {
    localStorage.clear();
    sessionStorage.clear();
    const databases = await indexedDB.databases();
    for (const db of databases) {
      if (db.name) indexedDB.deleteDatabase(db.name);
    }
    if ('caches' in window) {
      const cacheKeys = await caches.keys();
      await Promise.all(cacheKeys.map(key => caches.delete(key)));
    }
    console.log('✅ Limpieza completada. Recargando...');
    setTimeout(() => location.reload(), 500);
  } catch (error) {
    console.error('Error en limpieza:', error);
  }
})();

(function() {
  try {
    const ng = window.ng;
    if (!ng) {
      console.error('❌ Angular no detectado');
      return;
    }
    const appRef = ng.getComponent(document.body)?.appRef || ng.getApplicationRef?.();
    if (appRef && appRef.tick) {
      appRef.tick();
      console.log('✅ Change detection forzado');
    } else {
      console.error('❌ No se pudo acceder a ApplicationRef');
    }
  } catch (error) {
    console.error('Error:', error);
  }
})();

(function() {
  try {
    const ng = window.ng;
    if (!ng || !ng.getComponent) {
      console.error('❌ Angular DevTools no detectado');
      return;
    }
    const components = [];
    function scan(element) {
      const component = ng.getComponent(element);
      if (component) {
        components.push({
          name: component.constructor.name,
          element: element.tagName
        });
      }
      for (const child of element.children) {
        scan(child);
      }
    }
    scan(document.body);
    console.table(components);
    console.log(`📦 Total: ${components.length} componentes`);
  } catch (error) {
    console.error('Error:', error);
  }
})();

