(function() {
  try {
    const data = {};
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      data[key] = localStorage.getItem(key);
    }
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `localstorage-backup-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(url);
    console.log(`✅ Exportados ${Object.keys(data).length} items`);
  } catch (error) {
    console.error('Error:', error);
  }
})();

(function() {
  try {
    const originalFetch = window.fetch;
    window.fetch = async function(...args) {
      const start = performance.now();
      const url = args[0];
      const method = args[1]?.method || 'GET';
      console.log(`🌐 [${method}] ${url}`);
      try {
        const response = await originalFetch.apply(this, args);
        const duration = (performance.now() - start).toFixed(2);
        console.log(`✅ [${method}] ${url} - ${response.status} (${duration}ms)`);
        return response;
      } catch (error) {
        const duration = (performance.now() - start).toFixed(2);
        console.error(`❌ [${method}] ${url} - error (${duration}ms)`);
        throw error;
      }
    };
    console.log('✅ Monitor de peticiones HTTP activado');
  } catch (error) {
    console.error('Error:', error);
  }
})();

(function() {
  try {
    const perfData = performance.getEntriesByType('navigation')[0];
    const paintEntries = performance.getEntriesByType('paint');
    const resources = performance.getEntriesByType('resource');

    const fcp = paintEntries.find(e => e.name === 'first-contentful-paint')?.startTime;
    const ttfb = perfData?.responseStart - perfData?.requestStart;
    const loadTime = perfData?.loadEventEnd - perfData?.fetchStart;
    const totalResources = resources.length;
    const totalSize = resources.reduce((sum, r) => sum + (r.transferSize || 0), 0);

    console.log('📊 Métricas de rendimiento:');
    console.log(`   TTFB: ${ttfb?.toFixed(2) || 'N/A'} ms`);
    console.log(`   FCP: ${fcp?.toFixed(2) || 'N/A'} ms`);
    console.log(`   Load: ${loadTime?.toFixed(2) || 'N/A'} ms`);
    console.log(`   Recursos: ${totalResources}`);
    console.log(`   Tamaño total: ${(totalSize / 1024).toFixed(2)} KB`);
  } catch (error) {
    console.error('Error:', error);
  }
})();

(async function() {
  try {
    const firebase = window.firebase;
    if (!firebase) {
      console.error('❌ Firebase no detectado');
      return;
    }
    const auth = firebase.auth?.() || firebase.getAuth?.();
    if (!auth) {
      console.error('❌ Firebase Auth no disponible');
      return;
    }
    const user = auth.currentUser;
    if (user) {
      console.log('✅ Usuario autenticado:');
      console.log(`   UID: ${user.uid}`);
      console.log(`   Email: ${user.email}`);
      console.log(`   Email verificado: ${user.emailVerified}`);
      const token = await user.getIdTokenResult();
      console.log(`   Token expira: ${new Date(token.expirationTime).toLocaleString()}`);
    } else {
      console.log('🔓 No hay usuario autenticado');
    }
  } catch (error) {
    console.error('Error:', error);
  }
})();

(function() {
  try {
    const errors = [];
    const originalError = console.error;
    console.error = function(...args) {
      errors.push({ timestamp: new Date(), message: args.join(' ') });
      originalError.apply(console, args);
      if (errors.length > 10) errors.shift();
    };

    const div = document.createElement('div');
    div.style.cssText = `
      position: fixed;
      bottom: 10px;
      right: 10px;
      background: rgba(0,0,0,0.9);
      color: #ff4444;
      padding: 10px;
      border-radius: 5px;
      font-family: monospace;
      font-size: 12px;
      max-width: 400px;
      z-index: 99999;
      cursor: pointer;
    `;
    div.textContent = `🐛 Errores: ${errors.length}`;
    div.onclick = () => console.table(errors);
    document.body.appendChild(div);
    console.log('✅ Debugger de errores activado');
  } catch (error) {
    console.error('Error:', error);
  }
})();
